export const HARTHMERE_QUEST_COVERAGE_POLICY_V46 = JSON.parse(
  HARTHMERE_QUEST_COVERAGE_POLICY_V46_JSON,
) as {
  version: 46;
  requiredMainQuestCodes: readonly string[];
  requiredOptionalMainCodes: readonly string[];
  requiredSideQuestCodes: readonly string[];
  requiredStarterQuestIds: readonly string[];
  requiredRepeatableFamilies: readonly string[];
  minimumQuestCount: number;
  testRequirements: readonly string[];
};

export const HARTHMERE_QUEST_CATALOG_V46 = JSON.parse(
  HARTHMERE_QUEST_CATALOG_V46_JSON,
) as readonly any[];

export function getHarthmereQuestByIdV46(id: string) {
  return HARTHMERE_QUEST_CATALOG_V46.find((quest) => quest.id === id);
}

export function validateHarthmereQuestActivationV46(
  quest: any,
  context: HarthmereQuestContextV46,
): HarthmereQuestValidationResultV46 {
  const reasons: string[] = [];
  const completed = new Set(context.completedQuestIds ?? []);
  const flags = new Set(context.flags ?? []);

  if (!quest) return { ok: false, reasons: ["missing_quest"] };
  if (context.playerLevel < quest.levelBand.min) reasons.push("player_level_below_minimum");
  if (quest.levelBand.max && context.playerLevel > quest.levelBand.max + 10) reasons.push("player_far_above_soft_maximum");
  for (const prerequisite of quest.activeRules.prerequisiteQuestIds ?? []) {
    if (!completed.has(prerequisite)) reasons.push(`missing_prerequisite:${prerequisite}`);
  }
  for (const flag of quest.activeRules.requiredFlags ?? []) {
    if (!flags.has(flag)) reasons.push(`missing_flag:${flag}`);
  }
  if (!(quest.activeRules.timeOfDay ?? []).includes(context.timeOfDay)) reasons.push("wrong_time_of_day");
  if (!(quest.activeRules.activeHours ?? []).includes(context.hour)) reasons.push("wrong_hour");
  if (!(quest.activeRules.weather ?? []).includes(context.weather)) reasons.push("wrong_weather");
  if ((context.questStates?.[quest.id] ?? quest.activeRules.initialState) === "completed" && quest.repeatability === "once") {
    reasons.push("already_completed_once");
  }
  return { ok: reasons.length === 0, reasons };
}

export function getActiveHarthmereQuestsV46(context: HarthmereQuestContextV46) {
  return HARTHMERE_QUEST_CATALOG_V46.filter((quest) =>
    validateHarthmereQuestActivationV46(quest, context).ok,
  );
}

export function previewHarthmereQuestRewardsV46(questId: string) {
  const quest = getHarthmereQuestByIdV46(questId);
  if (!quest) return undefined;
  return {
    questId,
    title: quest.title,
    rewards: quest.rewards,
    grantPolicy: quest.testContract.rewardGrantPolicy,
  };
}

export function validateHarthmereQuestCatalogV46() {
  const ids = new Set<string>();
  const failures: string[] = [];
  for (const quest of HARTHMERE_QUEST_CATALOG_V46) {
    if (ids.has(quest.id)) failures.push(`duplicate quest id: ${quest.id}`);
    ids.add(quest.id);
    if (!quest.rewards || !quest.rewards.previewText) failures.push(`${quest.id} missing reward preview`);
    if (!quest.giverId && !quest.hidden) failures.push(`${quest.id} missing giverId or hidden trigger`);
    if (!quest.objectives?.length) failures.push(`${quest.id} missing objectives`);
    if (!quest.activeRules?.activationTestCases?.length) failures.push(`${quest.id} missing activation test cases`);
  }
  return { ok: failures.length === 0, failures };
}
